import requests

def get_user_licenses(token: str, user_id: str) -> list:
    r = requests.get(
        f"https://graph.microsoft.com/v1.0/users/{user_id}/licenseDetails",
        headers={"Authorization": f"Bearer {token}"}
    )
    r.raise_for_status()
    licenses = r.json().get("value", [])
    return [{"sku": lic["skuPartNumber"], "id": lic["skuId"]} for lic in licenses]

# Example output:
# [{"sku": "AAD_PREMIUM_P2", "id": "84a661c4-..."}, {"sku": "ENTERPRISEPREMIUM", "id": "..."}]

def has_p2(token: str, user_id: str) -> bool:
    P2_SKUS = {"AAD_PREMIUM_P2", "SPE_E5", "EMSPREMIUM"}
    lics = get_user_licenses(token, user_id)
    return any(l["sku"] in P2_SKUS for l in lics)

