    "displayName": "Require MFA - All Users",
    "state": "enabled",
    "conditions": {
        "users": {"includeUsers": ["All"], "excludeGroups": ["<break-glass-group-id>"]},
        "applications": {"includeApplications": ["All"]}
    },
