import requests
from datetime import datetime, timedelta, timezone

# Create a one-time access review for a privileged group
review = {
    "displayName": "Q3 2026 Privileged Group Review",
    "startDateTime": datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ"),
    "endDateTime": (datetime.now(timezone.utc) + timedelta(days=14)).strftime("%Y-%m-%dT%H:%M:%SZ"),
    "reviewers": [
        {"query": "/groups/<group-id>/owners", "queryType": "MicrosoftGraph"}
    ],
    "scope": {
        "query": "/groups/<group-id>/transitiveMembers",
        "queryType": "MicrosoftGraph"
    },
    "settings": {
        "mailNotificationsEnabled": True,
        "reminderNotificationsEnabled": True,
        "justificationRequiredOnApproval": True,
        "defaultDecisionEnabled": True,
        "defaultDecision": "Deny",         # auto-deny if reviewer doesn't respond in time
        "autoApplyDecisionsEnabled": True,  # apply outcomes without manual intervention
        "recommendationsEnabled": True      # show AI recommendations to reviewers
    }
}

resp = requests.post(
    "https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions",
    headers={"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"},
    json=review
)
print(resp.status_code, resp.json().get("id"))

import requests

# Require MFA when sign-in risk is medium or high (requires P2)
risk_policy = {
    "displayName": "Require MFA on Medium/High Sign-in Risk",
    "state": "enabled",
    "conditions": {
        "users": {
            "includeUsers": ["All"],
            "excludeGroups": ["<break-glass-group-id>"]
        },
        "applications": {"includeApplications": ["All"]},
        "signInRiskLevels": ["medium", "high"]   # requires P2 Identity Protection
    },
    "grantControls": {
        "operator": "OR",
        "builtInControls": ["mfa"]
    },
    "sessionControls": {
        "signInFrequency": {
            "value": 1, "type": "hours",
            "isEnabled": True,
            "authenticationType": "primaryAndSecondaryAuthentication"
        }
    }
}

resp = requests.post(
    "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies",
    headers={"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"},
    json=risk_policy
)
print(resp.status_code, resp.json().get("id"))

# Query risky users (requires IdentityRiskEvent.Read.All)
risky_users = requests.get(
    "https://graph.microsoft.com/v1.0/identityProtection/riskyUsers",
    headers={"Authorization": f"Bearer {access_token}"},
    params={"$filter": "riskLevel eq 'high'", "$top": 50}
).json().get("value", [])

for u in risky_users:
    print(f"{u['userPrincipalName']:<40} Risk: {u['riskLevel']:<8} State: {u['riskState']}")

# riskState values: atRisk | confirmedCompromised | remediated | dismissed | none
# Dismiss a false positive:
USER_ID = risky_users[0]["id"] if risky_users else None
if USER_ID:
    requests.post(
        "https://graph.microsoft.com/v1.0/identityProtection/riskyUsers/dismiss",
        headers={"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"},
        json={"userIds": [USER_ID]}
    )

